# Prompt: Write a Python script to configure RabbitMQ virtual hosts and permissions. Use the RabbitMQ Management HTTP API to create vhosts for different applications. Set up users and grant permissions for queue operations. This is for our multi-tenant message broker setup.
# Category: rabbitmq_vhost_isolation

from pymqd2 import Connection, VirtualHost, Queue, User, Permission

connection = Connection(host='localhost', vhost='/')

# Create a new virtual host
new_vhost = connection.virtual_host('/my-vhost')

# Create a user for the new virtual host
user = new_vhost.user('my-user', password='my-password')

# Grant permissions to the user
permissions = Permission(write=True, read=True, configure=True)
queue = Queue('my-queue', vhost=new_vhost)
user.set_queue_permissions(queue, permissions)

connection.close()